+
+func flashHeader(state *appState, msg string) {
+	if state == nil {
+		return
+	}
+	msg = strings.TrimSpace(msg)
+	if msg == "" {
+		return
+	}
+	state.headerFlash = msg
+	state.headerFlashAt = nowFn().Add(3 * time.Second)
+}
